() => {
  const out = {};
  out.url = location.href;
  const h1 = document.querySelector('h1');
  out.h1 = h1 ? h1.textContent.trim() : null;
  out.title = document.title;
  out.labels = Array.from(document.querySelectorAll('a[id^="labels"] span, a[href*="/labels/"] span, .js-issue-labels a')).map(e=>e.textContent.trim()).filter(Boolean);
  out.labels2 = Array.from(document.querySelectorAll('a.IssueLabel, span.IssueLabel')).map(e=>e.textContent.trim()).filter(Boolean);
  const commentsLink = Array.from(document.querySelectorAll('a,span')).find(el => /\bcomments?\b/i.test((el.textContent||'').trim()) && /\d/.test((el.textContent||'')));
  out.commentsText = commentsLink ? commentsLink.textContent.trim() : null;
  const timelineItems = document.querySelectorAll('[data-testid="issue-timeline"] .js-timeline-item').length;
  out.timelineItems = timelineItems;
  const m = document.body.innerText.match(/(\d+)\s+comments?/i);
  out.bodyMatch = m ? m[0] : null;
  out.bodyMatchNum = m ? m[1] : null;
  return out;
}

